def log(
    msg : mem,
    err : bool=False,
    *,
    _out=sys.stdout.buffer,
    _err=sys.stderr.buffer
) -> None:
    o = _err if err else _out
    o.write(msg)
    o.flush()




def logbar(
    txt : mem,
    cur : int, 
    tol : int,
    *,
    _el=mem(b'-' * 20),
    _fm=b'%b {%-20b} %3d%%',
    _mm=mem,
    _cl=color,
    _lg=log,
    _ch=[None]
) -> None:
    p = (cur * 20) // tol

    if p == _ch[0]:
        return
    

    _ch[0] = p
    b      = _el[0 : p]
  
    _lg(_cl( 'bar', _mm(_fm % (txt, b, p * 5)) ))




def gen_chars(
    *,
    _b=rand.randbelow,
    _g=rand.choice,
    _c=mem(b'0123456789_abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ'),
    _s=[None]
) -> mem:
    l = 4 + _b(250)
    b = array(l)
    p = mem(b)


    if _s[0] is None:
        _s[0] = _c[10:]


    while l:
        l -= 1
        p[l] = _g(_c)

    p[0] = _g(_s[0])


    return p




def gen_junk(
    cmd : bool=False,
    prc : bool=False,
    *, 
    _sp=b'\\n\\t'.join,
    _f0=b'"%b\\n"',
    _f1=b'__asm__ volatile ("%b");',
    _a=JUNK,
    _b=tuple( mem(j.tobytes().replace(b'%%', b'%')) for j in JUNK ),
    _r=rand.randbelow,
    _c=rand.choice
) -> mem:
    n = 1 + _r(10)


    return mem(
        (_f0 if cmd else _f1) % _sp( 
            _c(_b if prc else _a) for _ in range(n) 
        )
    )
    

 

def compress(
    dt  : mmap.mmap, 
    dln : int, 
    out : mem,
    *,
    _q=MSG[b'bar_compress'],
    _b=logbar
) -> mem:
    _g = dt.__getitem__
    _t = out.__setitem__


    i = j = 0 

    while i < dln:
        if (i & 0x3FFF) == 0:
            _b(_q, i, dln)


        r = 1
        c = _g(i)


        u = 127 if (dln - i) > 127 else dln - i

        while r < u:
            if _g(i + r) != c:
                break

            r += 1
        

        if r >= 3:
            _t(j,     0x80 | r)
            _t(j + 1, c       )

            j += 2
            i += r

        else:
            s = i
            u = dln if dln < (s + 126) else s + 126

            while i < u:
                if ( (i + 2) < dln ) and ( _g(i) == _g(i + 1) == _g(i + 2) ):
                    break

                i += 1


            l = i - s

            if l > 0:
                _t(j, l)
                j += 1
                
                out[j : j + l] = dt[s : i]
                j += l
    


    _b(_q, dln, dln)
    log(color('green', MSG[b'bar_done']))

    return out[0 : j]




def enc(
    dt   : mem, 
    key  : mem,
    salt : int, 
    *,
    _rep=False,
    _q=MSG[b'bar_enc'],
    _b=logbar
) -> mem:
    sz = len(dt)
    kl = len(key)


    if _rep:
        out = dt
    else:
        buf = array(sz)
        out = mem(buf)


    _g = dt.__getitem__
    _v = key.__getitem__
    _t = out.__setitem__


    i = salt & 0xFF
    
    for j in range(sz):
        if _rep and ( (j & 0x3FFF) == 0 ):
            _b(_q, j, sz)


        k = _v( (j + i) % kl )

        y = ( k ^ (j & 0xFF) ^ (j >> 8) ) & 0xFF
        x = ( _g(j) ^ y ^ i ) & 0xFF

        x = ( (x << 3) | (x >> 5) ) & 0xFF
        x = ( x + (y ^ 0xA5) ) & 0xFF


        _t(j, x)
        i = ( x ^ ((y << 1) & 0xFF) ^ (i >> 1) ) & 0xFF


    if _rep:
        _b(_q, sz, sz)
        log(color('green', MSG[b'bar_done']))


    return out




def writef(fp: bytes, dt: mem, *, _ck=CHUNK) -> bool:
    sz = len(dt)
    fd = -1
  
    try:

        fd = os.open(fp, os.O_RDWR|os.O_CREAT|os.O_TRUNC, 0o644)
        os.ftruncate(fd, sz)


        with mmap.mmap(
            fd, sz, 
            prot=mmap.PROT_WRITE, flags=mmap.MAP_SHARED
        ) as mp:
            mp.madvise(mmap.MADV_SEQUENTIAL)


            if sz <= _ck:
                mp[:] = dt
            else:
                mn = min

                for i in range(0, sz, _ck):
                    e         = mn(i + _ck, sz)
                    mp[i : e] = dt[i : e]


            mp.flush()

        return True
    except OSError:
        return False
    
    finally:
        if fd != -1:
            os.fsync(fd)
            os.close(fd)




def make_link_ld(
            fp : bytes, 
    entry : mem,    section : mem
) -> bool:
    script = array()



    addr = 0x400000 + (rand.randbelow(256) * 0x1000)



    script.extend(mem(
b'''/*  GENERATED_BY_ELFOBF_FOR(%b)  */\n\n\n\n
ENTRY(%b)
PHDRS { s PT_LOAD FLAGS(5); }
SECTIONS {

    . = 0x%X + SIZEOF_HEADERS;

    

    .%b : {''' % (fp, entry, addr, section)
    ))


    script.extend(rand.choice(SIGN))


    script.extend(mem(
b'''
        KEEP(*(.%b))
        *(.text*)
        *(.rodata*)
    } :s

    

    /DISCARD/ : {
        *(.*)
    }

}
''' % section
    ))



    ok = writef(PATH_LINK_LD, script)

    del addr, script
    return ok




