def c_compile(fp: bytes) -> int:
    sz  = 0
    out = PATH_OUTPUT % os.path.basename(fp)


    cmd = (
        CC, 
        b'-o', out,
        PATH_LOADER_C,
        b'-T', PATH_LINK_LD,
        *PARAM
    )


    code = sp_run(cmd, capture_output=True).returncode

    if code == 0:
        log(color('yellow', MSG[b'compile'])[0 : -1])
        log(color('green',  MSG[b'bar_done']))

        sp_run((PATH_SSTRIP_ELF, out), capture_output=True)
        log(color('yellow', MSG[b'sstrip'])[0 : -1])
        log(color('green',  MSG[b'bar_done']))

        sz = os.stat(out).st_size
    else:
        log(color('red', MSG[b'fail_compile'] % code))
    

    del cmd, code
    return (out, sz)




